function colt_editions_newest_first(): array {
    return array_reverse(colt_editions());
}

function find_colt_edition(string $slug): ?array {
    foreach (colt_editions() as $edition) {
        if ($edition['slug'] === $slug) {
            return $edition;
        }
    }
    return null;
}
